   242	    };
   243	    let mut last_index_to_remove = Some(hunks_to_remove_until_idx);
   244	    let hunk = &mut hunks[hunks_to_remove_until_idx];
   245	    let range = range_by_side(hunk);
   246	    if let Some(hunk_token_equal_till) = hunk_token_equal_till {
   247	        let orig_start = range.start;
   248	        let new_start = hunk_token_equal_till + 1;
   249	        range.start = new_start;
   250	        if Range::<u32>::is_empty(range) {
   251	            range.start = orig_start;
