   344	pub fn write_hunks(
   345	    hunks: &[Hunk],
   346	    input: &imara_diff::InternedInput<&[u8]>,
   347	    current_tokens: &[imara_diff::Token],
   348	    out: &mut Vec<u8>,
   349	) {
