   351	        let (tokens, range) = match hunk.side {
   352	            Side::Current => (current_tokens, &hunk.after),
   353	            Side::Other => (input.after.as_slice(), &hunk.after),
   354	            Side::Ancestor => (input.before.as_slice(), &hunk.before),
