   370	/// Find all hunks in `iter` which aren't from the same side as `hunk` and intersect with it.
   371	/// Also put `hunk` into `input` so it's the first item, and possibly put more hunks of the side of `hunk` so
   372	/// `iter` doesn't have any overlapping hunks left.
   373	/// Return `Some` if `intersecting` is non-empty after the operation, indicating overlapping hunks were found.
   374	pub fn take_intersecting(
   375	    iter: &mut Peekable<impl Iterator<Item = Hunk>>,
   376	    input: &mut Vec<Hunk>,
   377	    intersecting: &mut Vec<Hunk>,
   378	) -> Option<()> {
   379	    input.clear();
   380	    input.push(iter.next()?);
   381	    intersecting.clear();
   382	
   383	    fn left_overlaps_right(left: &Hunk, right: &Hunk) -> bool {
   384	        left.side != right.side
   385	            && (right.before.contains(&left.before.start)
   386	                || (right.before.is_empty() && right.before.start == left.before.start))
   387	    }
   388	
   389	    loop {
   390	        let hunk = input.last().expect("just pushed");
   391	        while iter.peek().filter(|b_hunk| left_overlaps_right(b_hunk, hunk)).is_some() {
   392	            intersecting.extend(iter.next());
   393	        }
   394	        // The hunks that overlap might themselves overlap with a following hunk of the other side.
   395	        // If so, split it so it doesn't overlap anymore.
   396	        let mut found_more_intersections = false;
   397	        while intersecting
   398	            .last_mut()
   399	            .zip(iter.peek_mut())
   400	            .filter(|(last_intersecting, candidate)| left_overlaps_right(candidate, last_intersecting))
   401	            .is_some()
   402	        {
   403	            input.extend(iter.next());
   404	            found_more_intersections = true;
   405	        }
   406	        if !found_more_intersections {
   407	            break;
   408	        }
   409	    }
   410	    Some(())
   411	}
