   433	pub fn collect_hunks(
   434	    algorithm: imara_diff::Algorithm,
   435	    input: &imara_diff::InternedInput<&[u8]>,
   436	    side: Side,
   437	    mut hunks: Vec<Hunk>,
   438	) -> Vec<Hunk> {
   439	    hunks.extend(imara_diff::Diff::compute(algorithm, input).hunks().map(|hunk| Hunk {
   440	        before: hunk.before,
   441	        after: hunk.after,
   442	        side,
   443	    }));
