use std::num::NonZero;
use gix_merge::blob::builtin_driver::text;
use gix_merge::blob::Resolution;

fn main() {
    // Minimal reproduction of the false conflict issue
    // base: short file with a comment line
    // ours: same file but with many lines inserted before the comment
    // theirs: base with the comment line deleted

    let base = b"line1\nline2\n// comment\nline4\nline5\n";
    let ours = b"line1\nline2\ninserted1\ninserted2\ninserted3\n// comment\nline4\nline5\n";
    let theirs = b"line1\nline2\nline4\nline5\n";

    let mut out = Vec::new();
    let mut input = imara_diff::InternedInput::new(&[][..], &[][..]);

    // Test with Myers
    let myers_opts = text::Options {
        diff_algorithm: imara_diff::Algorithm::Myers,
        conflict: text::Conflict::Keep {
            style: text::ConflictStyle::Merge,
            marker_size: NonZero::new(7).unwrap(),
        },
    };
    let labels = text::Labels {
        ancestor: Some("base".into()),
        current: Some("ours".into()),
        other: Some("theirs".into()),
    };

    let myers_res = text::function::merge(
        &mut out, &mut input, labels.clone(), ours, base, theirs, myers_opts,
    );
    println!("Myers resolution: {:?}", myers_res);
    println!("Myers output:\n{}", String::from_utf8_lossy(&out));
    let myers_has_conflict = matches!(myers_res, Resolution::Conflict);

    // Test with Histogram
    out.clear();
    let mut input2 = imara_diff::InternedInput::new(&[][..], &[][..]);
    let hist_opts = text::Options {
        diff_algorithm: imara_diff::Algorithm::Histogram,
        conflict: text::Conflict::Keep {
            style: text::ConflictStyle::Merge,
            marker_size: NonZero::new(7).unwrap(),
        },
    };

    let hist_res = text::function::merge(
        &mut out, &mut input2, labels, ours, base, theirs, hist_opts,
    );
    println!("Histogram resolution: {:?}", hist_res);
    println!("Histogram output:\n{}", String::from_utf8_lossy(&out));

    if myers_has_conflict {
        println!("\nBUG REPRODUCED: Myers produces false conflict while Histogram does not!");
    } else {
        println!("\nMyers resolved cleanly - bug not reproduced with this input.");
    }
}
