pub fn tokens(input: &[u8]) -> imara_diff::sources::ByteLines<'_> {
    imara_diff::sources::byte_lines(input)
}

/// Trim leading and trailing lines from `hunk` that are identical in both `before` and `after`.
/// This narrows the hunk to only the actually-changed lines, which helps avoid false overlap
/// detection in the 3-way merge when diff algorithms (like Myers) include extra context.
pub fn trim_hunk_context(
    hunk: &mut Hunk,
    input: &imara_diff::InternedInput<&[u8]>,
    current_tokens: &[imara_diff::Token],
) {
    let (before_tokens, after_tokens) = match hunk.side {
        Side::Current => (&input.before, current_tokens),
        Side::Other => (&input.before, input.after.as_slice()),
        Side::Ancestor => return,
    };

    let b_start = hunk.before.start as usize;
    let b_end = hunk.before.end as usize;
    let a_start = hunk.after.start as usize;
    let a_end = hunk.after.end as usize;

    let b_slice = &before_tokens[b_start..b_end];
    let a_slice = &after_tokens[a_start..a_end];

    // Trim leading context
    let mut trim_leading: u32 = 0;
    for (b, a) in b_slice.iter().zip(a_slice.iter()) {
        if input.interner[*b] == input.interner[*a] {
            trim_leading += 1;
        } else {
            break;
        }
    }

    // Trim trailing context
    let remaining = b_slice.len().min(a_slice.len()).saturating_sub(trim_leading as usize);
    let mut trim_trailing: u32 = 0;
    for i in 0..remaining {
        let b = b_slice[b_slice.len() - 1 - i];
        let a = a_slice[a_slice.len() - 1 - i];
        if input.interner[b] == input.interner[a] {
            trim_trailing += 1;
        } else {
            break;
        }
    }

    hunk.before.start += trim_leading;
    hunk.before.end -= trim_trailing;
    hunk.after.start += trim_leading;
    hunk.after.end -= trim_trailing;
}

