#[test]
    fn myers_false_conflict_with_insertion_before_deletion() {
        // Reproduction of: Myers produces false conflict where Histogram resolves cleanly.
        // base has a comment line, ours inserts lines before the comment, theirs deletes the comment.
        let base = b"line1\nline2\n// comment\nline4\nline5\n";
        let ours = b"line1\nline2\ninserted1\ninserted2\ninserted3\n// comment\nline4\nline5\n";
        let theirs = b"line1\nline2\nline4\nline5\n";

        for diff_algorithm in [imara_diff::Algorithm::Myers, imara_diff::Algorithm::Histogram] {
            let options = builtin_driver::text::Options {
                diff_algorithm,
                conflict: builtin_driver::text::Conflict::Keep {
                    style: builtin_driver::text::ConflictStyle::Merge,
                    marker_size: 7.try_into().unwrap(),
                },
            };
            let mut input = imara_diff::InternedInput::default();
            let mut out = Vec::new();
            let actual = builtin_driver::text(
                &mut out,
                &mut input,
                Default::default(),
                ours,
                base,
                theirs,
                options,
            );
            assert_eq!(
                actual,
                Resolution::Complete,
                "{diff_algorithm:?}: expected clean merge, got {actual:?}\noutput: {}",
                std::str::from_utf8(&out).unwrap_or("non-utf8"),
            );
        }
    }

