action.new_str:
match style {
                    ConflictStyle::Merge => {
                        if contains_lines(our_hunks) || contains_lines(their_hunks) {
                            // A pure insertion on one side and a pure deletion on the other
                            // are independent changes that don't conflict. An insertion adds
                            // content before the affected ancestor line, while a deletion
                            // removes that line - they operate on different parts of the file.
                            let our_non_ancestor: Vec<_> =
                                our_hunks.iter().filter(|h| h.side != Side::Ancestor).collect();
                            let their_non_ancestor: Vec<_> =
                                their_hunks.iter().filter(|h| h.side != Side::Ancestor).collect();
                            let our_only_inserts = !our_non_ancestor.is_empty()
                                && our_non_ancestor
                                    .iter()
                                    .all(|h| h.before.is_empty() && !h.after.is_empty());
                            let their_only_inserts = !their_non_ancestor.is_empty()
                                && their_non_ancestor
                                    .iter()
                                    .all(|h| h.before.is_empty() && !h.after.is_empty());
                            let our_only_deletes = !our_non_ancestor.is_empty()
                                && our_non_ancestor
                                    .iter()
                                    .all(|h| !h.before.is_empty() && h.after.is_empty());
                            let their_only_deletes = !their_non_ancestor.is_empty()
                                && their_non_ancestor
                                    .iter()
                                    .all(|h| !h.before.is_empty() && h.after.is_empty());
                            let independent_changes =
                                (our_only_inserts && their_only_deletes) || (their_only_inserts && our_only_deletes);
                            if independent_changes {
                                // Both changes are independent: apply both.
                                write_hunks(our_hunks, input, &current_tokens, out);
                                write_hunks(their_hunks, input, &current_tokens, out);
                            } else {
                                resolution = Resolution::Conflict;
                                write_conflict_marker(out, b'<', current_label, marker_size, nl);
                                write_hunks(our_hunks, input, &current_tokens, out);
                                write_conflict_marker(out, b'=', None, marker_size, nl);
                                write_hunks(their_hunks, input, &current_tokens, out);
                                write_conflict_marker(out, b'>', other_label, marker_size, nl);
                            }
                        }
                    }

