                            // are independent changes that don't conflict. An insertion adds
                            // content before the affected ancestor line, while a deletion
                            // removes that line - they operate on different parts of the file.
                            let our_only_inserts = our_hunks
                                .iter()
                                .filter(|h| h.side != Side::Ancestor)
                                .all(|h| h.before.is_empty() && !h.after.is_empty());
                            let their_only_inserts = their_hunks
                                .iter()
                                .filter(|h| h.side != Side::Ancestor)
                                .all(|h| h.before.is_empty() && !h.after.is_empty());
                            let our_only_deletes = our_hunks
                                .iter()
                                .filter(|h| h.side != Side::Ancestor)
                                .all(|h| !h.before.is_empty() && h.after.is_empty());
                            let their_only_deletes = their_hunks
                                .iter()
                                .filter(|h| h.side != Side::Ancestor)
                                .all(|h| !h.before.is_empty() && h.after.is_empty());
