    builtin_driver::text::{
        utils::{
            assure_ends_with_nl, collect_hunks, contains_lines, detect_line_ending, detect_line_ending_or_nl,
            fill_ancestor, hunks_differ_in_diff3, take_intersecting, tokens, trim_hunk_context, write_ancestor,
            write_conflict_marker, write_hunks, zealously_contract_hunks, Hunk, Side,
        },
        Conflict, ConflictStyle, Labels, Options,
    },
    Resolution,
};

